{"code": "import json
import re

book_file_path = locals()['var_functions.query_db:10']
reviews_file_path = locals()['var_functions.query_db:6']

# Load the query results
with open(book_file_path, 'r') as f:
    books_data = json.load(f)

with open(reviews_file_path, 'r') as f:
    reviews_data = json.load(f)

# Extract year from details field for all books
book_year_info = []

for book in books_data:
    details = book.get('details', '')
    year = None

    # Try multiple patterns to find years
    date_patterns = [
        r'(?:January|February|March|April|May|June|July|August|September|October|November|December)\s+\d{1,2},\s+(\d{4})',
        r'on\s+(\d{1,2})\s+(?:January|February|March|April|May|June|July|August|September|October|November|December)\s+(\d{4})',
        r'\b(19\d{2}|20\d{2}|18\d{2}|2100|1945|1940|1939)\b',
    ]

    for pattern in date_patterns:
        matches = re.findall(pattern, details, re.IGNORECASE)
        if matches:
            year_str = matches[0]
            if isinstance(year_str, tuple):
                year = int(year_str[1])  # For patterns with month/date/year
            else:
                year = int(year_str)
            break

    # Fallback: look for any 4-digit year between 1800-2099
    if not year:
        year_matches = re.findall(r'\b(1\d{3}|2\d{3})\b', details)
        for y in year_matches:
            y_int = int(y)
            if 1800 <= y_int <= 2023:
                year = y_int
                break

    if year:
        decade = f"{(year // 10) * 10}s"
        book_year_info.append({
            'book_id': book.get('book_id'),
            'year': year,
            'decade': decade
        })
    else:
        book_year_info.append({
            'book_id': book.get('book_id'),
            'year': None,
            'decade': None
        })

# Create mapping from book_id to decade
book_to_decade = {item['book_id']: item['decade'] for item in book_year_info}

# Extract number from purchase_id and book_id for joining
reviews_by_number = {}
for review in reviews_data:
    pid = review.get('purchase_id', '')
    match = re.search(r'_(\d+)$', pid)
    if match:
        num = int(match.group(1))
        if num not in reviews_by_number:
            reviews_by_number[num] = []
        reviews_by_number[num].append(review)

# Join reviews with book decades
matched_reviews = []
decade_reviews = {}

for book in books_data:
    book_id = book.get('book_id', '')
    bmatch = re.search(r'_(\d+)$', book_id)
    if bmatch:
        book_num = int(bmatch.group(1))
        decade = book_to_decade.get(book_id)

        if decade and book_num in reviews_by_number:
            for review in reviews_by_number[book_num]:
                matched_reviews.append({
                    'book_id': book_id,
                    'decade': decade,
                    'rating': float(review.get('rating', 0))
                })

                if decade not in decade_reviews:
                    decade_reviews[decade] = []
                decade_reviews[decade].append(float(review.get('rating', 0)))

# Calculate statistics per decade
decade_stats = {}
for decade, ratings in decade_reviews.items():
    unique_books = len(set([r['book_id'] for r in matched_reviews if r['decade'] == decade]))
    if unique_books >= 10:  # At least 10 distinct books
        decade_stats[decade] = {
            'avg_rating': sum(ratings) / len(ratings),
            'total_ratings': len(ratings),
            'unique_books': unique_books
        }

# Sort by average rating
sorted_decades = sorted(decade_stats.items(), key=lambda x: x[1]['avg_rating'], reverse=True)

result = {
    "total_matched_reviews": len(matched_reviews),
    "decades_with_10plus_books": len(decade_stats),
    "top_decades": sorted_decades[:5],
    "all_decades": [(d, s['avg_rating'], s['unique_books']) for d, s in sorted_decades]
}

print("__RESULT__:")
print(json.dumps(result))"}
